window.__QUIZ_DATA__=[{"id":"theory>Commerce>2012>1>a","subject":"Commerce","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"INTRODUCTION TO COMMERCE : MEANING & SCOPE","question":"The chart below gives the main divisions of Commerce, complete the chart by filling in the blank spaces labelled (i) to (viii)","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"- Trade  - Foreign Trade  - Retail  - Wholesale  - Banking   - Advertising  - Transport  -  Warehousing","marks":"10","difficulty":"2"},{"id":"theory>Commerce>2012>1>b>i","subject":"Commerce","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"OCCUPATION : MEANING & IMPORTANCE","question":"Explain Primary production and give one example.","images":[],"marking_scheme":"Primary Production : This involves  people whose activities is to extract natural resources from soil and sea. examples: Forestry, mining, hunting, fishing, farming etc.","marks":"3","difficulty":"1"},{"id":"theory>Commerce>2012>1>b>ii","subject":"Commerce","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PRODUCTION : FACTORS OF PRODUCTION","question":"Explain Secondary production and give one example.","images":[],"marking_scheme":"Secondary Production : This involves the stage in which the workers engaging in changing raw materials extracted from soil or sea into finished goods e.g shoes and bags making","marks":"4","difficulty":"1"},{"id":"theory>Commerce>2012>1>b>iii","subject":"Commerce","year":"2012","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"PRODUCTION : FACTORS OF PRODUCTION","question":"Explain Tertiary production and give one example","images":[],"marking_scheme":"Tertiary Production: This the provision and commercial and professional activities/ services to satisfy the wants of human.e.g Insurance,Policy,Teachers, etc.","marks":"4","difficulty":"1"},{"id":"theory>Commerce>2012>2>a>i","subject":"Commerce","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES","question":"Explain limited liability","images":[],"marking_scheme":"Limited Liability: This means that in the event of winding up, the shareholders can only lose the value attached to the share they contributed.","marks":"2","difficulty":"1"},{"id":"theory>Commerce>2012>2>a>ii","subject":"Commerce","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES","question":"What is Separate legal entity?","images":[],"marking_scheme":"Seperate Legal Entity: This means the business is different from the owners. The business can sue and can be sued in his own name without involving the owner of the business.","marks":"2","difficulty":"1"},{"id":"theory>Commerce>2012>2>a>iii","subject":"Commerce","year":"2012","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES","question":"What is Certificate of incorporation?","images":[],"marking_scheme":"Certificate of Incorporation: Is given out as an evidence by register of companies that all the requirement of the Act in respect of the registration has been fulfilled by the companies and is duty registered under the act.","marks":"2","difficulty":"1"},{"id":"theory>Commerce>2012>2>a>iv","subject":"Commerce","year":"2012","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE","question":"What does participating preference shares mean?","images":[],"marking_scheme":"Participating Preference shares: The holders participate or takes part in the sharing of the profit that remains after settling other shareholder.","marks":"2","difficulty":"2"},{"id":"theory>Commerce>2012>2>a>v","subject":"Commerce","year":"2012","type":"Theory","sub_label":"v","group":"CLOSENESS","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE","question":"What does ordinary shares mean?","images":[],"marking_scheme":"Ordinary Shares is also known as equity. The ordinary shareholders are real owners of the business. The holders are the risk bearers and they receive their dividends after all other shares have been paid.","marks":"2","difficulty":"2"},{"id":"theory>Commerce>2012>2>b","subject":"Commerce","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES","question":"State five advantages of public corporation","images":[],"marking_scheme":"i) They provide infrastructural facilities eg road,schools etc  ii) Sufficient capital to expand enterprises is available  iii) They reduce the exploitation of consumers.  iv) It is a legal entity, its can sue and be sued on his own.  v)Provides employment opportunities to the unemployed.  vi) The government is able to generate revenue  vii) It can last for longer period, there is perpetual existence.","marks":"10","difficulty":"1"},{"id":"theory>Commerce>2012>3>a","subject":"Commerce","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENT OF MARKETING : MARKETING MIX","question":"What is channel of distribution?","images":[],"marking_scheme":"Channel of distribution is the path through which goods are moved from the manufactural/ producer to the final consumers. The channel of distribution is:     producer ------> wholesaler ------> retailer ------. consumers","marks":"3","difficulty":"1"},{"id":"theory>Commerce>2012>3>b","subject":"Commerce","year":"2012","type":"Theory","sub_label":"b","group":"","topic":"ELEMENT OF MARKETING : MARKETING MIX","question":"With the aid of diagrams, show four examples of channel of distribution","images":["data:image/png;base64,"],"marking_scheme":"","marks":"5","difficulty":"3"},{"id":"theory>Commerce>2012>3>c","subject":"Commerce","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"TRADE (1) : HOME TRADE: WHOLESALE TRADE","question":"Explain five advantages of home trade over foreign trade .","images":[],"marking_scheme":"i) Home is within the same territory.  ii) The risk involved in home trade is low.  iii) The mobility of factors of production is not restricted in home trade.  iv) Home trade make use of the same currency.  v) There is little/no language problem in home trade.  vi) There is no problem of transport and communication in home trade.  vii) There is no cultural problem in home trade.","marks":"12","difficulty":"2"},{"id":"theory>Commerce>2012>4>a","subject":"Commerce","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE","question":"What is credit?","images":[],"marking_scheme":"Credit is the act of transferring goods and services from the seller to the buyer to enjoy and use it without giving the value to the seller immediately.","marks":"3","difficulty":"1"},{"id":"theory>Commerce>2012>4>b","subject":"Commerce","year":"2012","type":"Theory","sub_label":"b","group":"","topic":"AIDS TO TRADE: INSURANCE : PRINCIPLES","question":"List and explain six principles of insurance","images":[],"marking_scheme":"i) Indemnity ii) Insurable interest iii) Subrogation iv)Contribution v) Proximate cause vi)ultermost good faith vii) Abandonment   i)Indemnity: is the compensation given to the insured by the insurer in the event of his suffering a loss. Under this principle, the insured will be given compensation for a loss suffered.   ii) Insurable interest: This is one of the principles of insurance which states that, one can only insure properties that will bring loss or liabilities to him upon destruction.   iii)Subrogation: States that the insurer can take over the right of the insured once he has been compensated for a loss.  iv)Contribution: The principle states that where a person has insured a certain risk with many insurance company, he cannot claim compensation in full from each of the insurance companies.    v)Proximate Cause: This principle states that only the losses or liabilities which arise from the direct and immediate cause of the event insured against indemnified.   vi)Utmost Good Faith(Uberrimae Fides): This principle states that any insurance contract, all relevant information that will affect the validity of the agreement must be disclosed by the parties.   vii) Abandonment:  States that, if the most of repairing a damaged insured object exceeds the value, The object should be abandoned. The insurance company will sell the object/parts no matter the value.","marks":"17","difficulty":"2"},{"id":"theory>Commerce>2012>5>a","subject":"Commerce","year":"2012","type":"Theory","sub_label":"a","group":"","topic":"AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION","question":"Explain five factors affecting the choice of transport of frozen product.","images":[],"marking_scheme":"Temperature Control: Transport must have reliable refrigeration to maintain the required temperature.    Speed: Faster methods like air freight are preferred to minimize transit time and prevent thawing.    Cost: Cost-effective options must balance with the need for maintaining product quality.    Distance and Route: Longer distances might use sea freight, while shorter routes could use road transport.    Regulations: Compliance with food safety and transportation regulations is essential.","marks":"10","difficulty":"2"},{"id":"theory>Commerce>2012>5>b","subject":"Commerce","year":"2012","type":"Theory","sub_label":"b","group":"","topic":"AIDS TO TRADE: TRANSPORTATION : ADVANTAGES & DISADVANTAGES OF TRANSPORTATION","question":"State five disadvantages of air transport.","images":[],"marking_scheme":"i) When accident occurs it is very fatal,its can claim the lives of all  passenger on board.  ii) The cost of buying and maintaining aircraft is very high.  iii) It is not suitable for  heavy and bulky goods.  iv) The cost of air fare or charges is very high.  v)Aeroplane cannot land anywhere except the airport.  vi) Weather may disturb flight ,therefore is limited by weather conditions.  vii) Airports are located far away from the people.","marks":"10","difficulty":"2"},{"id":"theory>Commerce>2012>6>a","subject":"Commerce","year":"2012","type":"Theory","sub_label":"a","group":"","topic":"ELEMENT OF MARKETING : MARKET SEGMENTATION","question":"Define the term market segmentation","images":[],"marking_scheme":"Market Segmentation is the division of a whole market to a market groups,that consist of people who have similar product needs","marks":"2","difficulty":"1"},{"id":"theory>Commerce>2012>6>b","subject":"Commerce","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENT OF MARKETING : MARKET SEGMENTATION","question":"List five factors that influence market segmentation","images":[],"marking_scheme":"i) Measurable  ii)Accessibility    iii) Durable  iv) Gender of buyer  v)Population  vi) Consumers taste  vii) Easy to identify and measure  viii) Competition  ix) Viability  x) Unique  xi) Appropriate  xii) Meaningful","marks":"8","difficulty":"2"},{"id":"theory>Commerce>2012>6>c","subject":"Commerce","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"AIDS TO TRADE: ADVERTISING : ADVANTAGES AND DISADVANTAGES","question":"State five advantages of advertising","images":[],"marking_scheme":"Advantages of Advertising   - Creation of Awareness: It helps in creating awareness for a product.   - It provide information about existing goods.   - It increase the profit of an organisation.   - It can lead to increase in production as more goods will be demanded.   - Technical information about a product: Advertising provides information that are needed by the consumer information about quantity, price changes and special offer.","marks":"10","difficulty":"2"},{"id":"theory>Commerce>2012>7>a","subject":"Commerce","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT","question":"What is contract?","images":[],"marking_scheme":"A contract means an agreement between two or more parties creating an obligation and must have a legal backing.","marks":"3","difficulty":"1"},{"id":"theory>Commerce>2012>7>b","subject":"Commerce","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT","question":"List five elements of valid contract.","images":[],"marking_scheme":"i) Offer  ii) Unqualified acceptance  iii) Valuable consideration  iv) Genuineness of consent.  v) Intension to create legal relations  vi) Contractual capacity  vii) Formality of a contract  viii) Legality of objects of the contract","marks":"7","difficulty":"2"},{"id":"theory>Commerce>2012>7>c","subject":"Commerce","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"LEGAL ASPECT OF BUSINESS: CONTRACT : REMEDIES FOR A BREACH OF CONTRACT","question":"Explain four ways by which a contract may be discharged","images":[],"marking_scheme":"i) By performance: If both parties have perform their duties  ii) By breach:   If a party fail to perform his part of the contract.  iii) By agreement of the parties: If both parties agree to end it  iv) By frustration: If the subject matters is destroyed by an Act of God.  v) Bankrupt: If either of the parties is bankrupt.  vi) Illegality of object: If the subject matter is illegal e.g prostitution, thief etc","marks":"10","difficulty":"3"},{"id":"theory>Commerce>2012>8>a","subject":"Commerce","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"TRADE ( 2) : DOCUMENT USED IN INTERNATIONAL TRADE","question":"Explain Indent as used in international trade.","images":[],"marking_scheme":"Indent: Is an order to purchase goods sent by the importer of his agent.","marks":"4","difficulty":"2"},{"id":"theory>Commerce>2012>8>b","subject":"Commerce","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"TRADE ( 2) : DOCUMENT USED IN INTERNATIONAL TRADE","question":"Explain Bill of lading as used in international trade.","images":[],"marking_scheme":"Bill of Lading: Its empower the importer to claim the goods when it is presented an is an evidence that goods are shipped.","marks":"4","difficulty":"2"},{"id":"theory>Commerce>2012>8>c","subject":"Commerce","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"TRADE ( 2) : DOCUMENT USED IN INTERNATIONAL TRADE","question":"Explain the Consular invoice as used in international trade.","images":[],"marking_scheme":"A consular invoice is a specialized document used in international trade that serves as proof of the details of a shipment. It is used to verify the authenticity and accuracy of the shipment details, including the nature, quantity, and value of the goods being exported. This ensures that the goods comply with the importing country's regulations and requirements.","marks":"4","difficulty":"2"},{"id":"theory>Commerce>2012>8>d","subject":"Commerce","year":"2012","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"TRADE ( 2) : DOCUMENT USED IN INTERNATIONAL TRADE","question":"Explain Certificate of origin as used in international trade.","images":[],"marking_scheme":"Certificate of Origin: Its shows the country where goods are imported from or are produced.","marks":"4","difficulty":"2"},{"id":"theory>Commerce>2012>8>e","subject":"Commerce","year":"2012","type":"Theory","sub_label":"e","group":"CLOSENESS","topic":"TRADE ( 2) : DOCUMENT USED IN INTERNATIONAL TRADE","question":"Explain Bill of exchange as used in international trade.","images":[],"marking_scheme":"Bill of Exchange: is an unconditional order written and signed by the person giving it, requesting the person who sent it to,pay a certain amount of money at a particular time","marks":"4","difficulty":"2"},{"id":"theory>Commerce>2012>9>a","subject":"Commerce","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES","question":"Differentiate between Nationalization and Indigenization","images":[],"marking_scheme":"Nationalization: Refers to the process where a government takes control of private assets or industries and transfers ownership from private individuals or companies to the state. This often involves the complete or partial acquisition of businesses by the government.    Indigenization: Refers to the process of transferring ownership and control of industries or businesses from foreign entities to local individuals or groups within a country. It focuses on increasing local participation and control.    Nationalization is the transfer from private to state ownership of enterprises for economic social and political reasons, WHILE Indigenization is the act of using law to make indigene of a country to participate actively in the industrial sector of their economy.","marks":"8","difficulty":"3"},{"id":"theory>Commerce>2012>9>b","subject":"Commerce","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES","question":"State six reasons why a country would indigenize some industries","images":[],"marking_scheme":"i) It  increase the participation of indigenes in their economy.  ii) Its promote industralization.  iii)The country will maintain economy stability.  iv) It will increase the standard of living of the people.  v) The prices of goods will be reduced and stabilized.  vi) Its create job opportunity for indigene of a country.  vii) It will reduce the rate at which one country depend on another country.  viii) Its reduce the rate at which an economy is controlled by foreign economic buccanears.","marks":"12","difficulty":"3"},{"id":"theory>Commerce>2012>10>a","subject":"Commerce","year":"2012","type":"Theory","sub_label":"a","group":"FINAL","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL","question":"Ade Company Limited has an authorized capital of 80,000 shares of \u20a620 each, out of which 30,000 shares have been fully subscribed by the public and alloted as at 31st March 2006. Other assets and liabilities were:   \u20a6Creditors 35 000Motor Van 90 000Buildings 65 000Stock 60 000Debtors 15 000Cash 5 000    You are required to calculate the Issued capital","images":[],"marking_scheme":"ADE COMPANY LIMITED  Authorised capital = 80,000 shares @ \u20a620 = \u20a61,600,000   Issued Capital: This is part of the authorised capital that the company had issued out = 30,000 shares @ \u20a620    = \u20a6600,000","marks":"5","difficulty":"3"},{"id":"theory>Commerce>2012>10>b","subject":"Commerce","year":"2012","type":"Theory","sub_label":"b","group":"FINAL","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL","question":"Ade Company Limited has an authorized capital of 80,000 shares of \u20a620 each, out of which 30,000 shares have been fully subscribed by the public and alloted as at 31st March 2006. Other assets and liabilities were:   \u20a6Creditors 35 000Motor Van 90 000Buildings 65 000Stock 60 000Debtors 15 000Cash 5 000  You are required to calculate the unissued capital","images":[],"marking_scheme":"ADE COMPANY LIMITED     Authorised capital = 80,000 shares @ \u20a620 = \u20a61,600,000      Unissued Capital = Authorised Capital - Issued Capital      = \u20a61,000,000 = \u20a61,600,000 - \u20a6600,000     or      Authorised Capital = \u20a61,600,000      Less Issued Capital = -  \u20a6600,000      Unissued Capital = \u20a61,000,000","marks":"5","difficulty":"3"},{"id":"theory>Commerce>2012>10>c","subject":"Commerce","year":"2012","type":"Theory","sub_label":"c","group":"FINAL","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL","question":"Ade Company Limited has an authorized capital of 80,000 shares of \u20a620 each, out of which 30,000 shares have been fully subscribed by the public and alloted as at 31st March 2006. Other assets and liabilities were:   \u20a6Creditors 35 000Motor Van 90 000Buildings 65 000Stock 60 000Debtors 15 000Cash 5 000  You are required to calculate the Total Assets","images":[],"marking_scheme":"ADE COMPANY LIMITED   Authorised capital = 80,000 shares @ \u20a620 = \u20a61,600,000   Total Asset: This is the summation of both fixed Asset and current asset. It can also be called capital employed.   ADE COMPANY LIMITED     Fixed Assets  \u20a6 \u20a6Building 65 000  Motor van 90 000 155 000 Current Assets   Stocks 60 000  Debtors 15 000  Cash 5 000 80 000  235 000","marks":"5","difficulty":"3"},{"id":"theory>Commerce>2012>10>d","subject":"Commerce","year":"2012","type":"Theory","sub_label":"d","group":"FINAL","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : TYPES OF CAPITAL","question":"Ade Company Limited has an authorized capital of 80,000 shares of \u20a620 each, out of which 30,000 shares have been fully subscribed by the public and alloted as at 31st March 2006. Other assets and liabilities were:   \u20a6Creditors 35 000Motor Van 90 000Buildings 65 000Stock 60 000Debtors 15 000Cash 5 000  You are required to calculate the Working capital","images":[],"marking_scheme":"ADE COMPANY LIMITED   Authorised capital = 80,000 shares @ \u20a620 = \u20a61,600,000    Working Capital:This is also called circulating capital. It is the amount used for the day to day running of the business. It is calculated thus: Current Asset - Asset liabilities.   Current Assets \u20a6Stocks 60 000Debtors 15 000Cash 5 000 80 000Less: Current liabilitiesCreditors (35,000) Working Capital 45,000","marks":"5","difficulty":"3"}];